ValidationRule.errorConditionFormula:
AND(
    $RecordType.Id <> "012bf000002etUUAAY",
    OR(
        AND(
            NOT(ISBLANK(Phone)),
            ISBLANK(TRIM(Phone_Ext__c))
        ),
        AND(
            NOT(ISBLANK(TRIM(Phone_Ext__c))),
            OR(
                LEN(TRIM(Phone_Ext__c)) > 4,
                NOT(REGEX(TRIM(Phone_Ext__c), "^\\+[0-9]{1,3}$"))
            )
        )
    )
)
